import React, { useState, useEffect, useRef } from 'react';
import './css_comp/seat_selection.css';
import { useNavigate } from 'react-router-dom';

export default function Seat_selection(props) {

  const seat = [];
  const [booked, setBooked] = useState([18, 19, 30]);
  const [selected, setSelected] = useState([]);
  const compartment = props.compartment;

  const [sortedCompartment, setSortedCompartment] = useState([]);
  const [currentCompartment, setCurrentCompartment] = useState();
  const [selectedCompartment, setSelectedCompartment] = useState();
  const column = 5;

  // Calculated `row` based on current compartment's total seats, re-calculates on currentCompartment change
  const navigate=useNavigate()
  const row = currentCompartment ? (Math.floor(currentCompartment.total_seat / column)) : 0;

  // Initial sorting and setting compartments
  useEffect(() => {
    const sorted = [...compartment].sort((item1, item2) =>
      item1.remaining_seat < item2.remaining_seat ? 1 : -1
    );
    setSortedCompartment(sorted);
    setCurrentCompartment(sorted[0]); // set initial compartment
    setSelectedCompartment(sorted[0]?.compartment_id); // set initial selected ID
  }, [compartment]);

  // Handle compartment selection change
  const changeCompartment = (e) => {
    const key_value = e.target.value;
    const chosenCompartment = sortedCompartment.find((item) => item.compartment_id == key_value);

    setCurrentCompartment(chosenCompartment);
    setSelectedCompartment(key_value);
  };

  // Seat booking handler
  const handleBooked = (seatNumber) => {
    setSelected((prevSelected) =>
      prevSelected.includes(seatNumber)
        ? prevSelected.filter((item) => item !== seatNumber)
        : [...prevSelected, seatNumber]
    );
  };

  // Generate seat layout based on current row calculation
  let count = 1;
  for (let i = 0; i < row; i++) {
    const rowSeats = [];
    for (let j = 0; j < column + 1; j++) {
      if (j === 2) {
        rowSeats.push(<div id="space" key={`${i}-${j}`} />);
      } else {
        const currentCount = count;
        if (booked.includes(count)) {
          rowSeats.push(<div id='seat-booked' key={currentCount}>{count}</div>);
        } else if (selected.includes(currentCount)) {
          rowSeats.push(
            <div id='seat-selected' onClick={() => handleBooked(currentCount)} key={currentCount}>
              {count}
            </div>
          );
        } else {
          rowSeats.push(
            <div id='seat' onClick={() => handleBooked(currentCount)} key={currentCount}>
              {count}
            </div>
          );
        }
        count++;
      }
    }
    seat.push(rowSeats);
  }

  return (
    <>
      <div id='select_show'>
        <div id='caution'>Choose your seat(s)** Maximum 4 seats can be booked at a time.</div>
        <hr />
        <div id='caution'>
          <p>To know seat number(s), rest the cursor on your desired seat(s). Click on it to select or deselect.</p>
        </div>
        <section className='parent'>
          <div className='left-child'>
            <h2>Select Coach</h2>
            <select name="" value={selectedCompartment} onChange={changeCompartment} id="select-coach">
              {sortedCompartment.map((item) => (
                <option key={item.compartment_id} value={item.compartment_id}>
                  {item.compartment_name}-{item.remaining_seat}
                </option>
              ))}
            </select>
            <div className="seat-status">
              <div className='available'>
                <p>Available</p>
                <div id='box' />
              </div>
              <div className='available' id='booked'>
                <p>Booked</p>
                <div id='box' />
              </div>
              <div className='available' id='selected'>
                <p>Selected</p>
                <div id='box' />
              </div>
            </div>
            <div className="seat-choose">
              {seat.map((rowSeats, index) => (
                <div id='row' key={index}>
                  {rowSeats}
                </div>
              ))}
            </div>
          </div>
          <div className="right-child">
            <h2>Seat Details</h2>
            <div id='ticket-details'>
              <p>Class</p>
              <p>Seats</p>
              <p>Fare</p>
            </div>
            <div id='tickets'>here tickets</div>
            <div id='Total-amount'>
              <h3>Total: ৳ 0 </h3>
            </div>
            <div id='btn-purchase'>
              <button onClick={() => navigate('/passangerinfo')} id='btn-continue-purchase'>
                CONTINUE PURCHASE
              </button>
            </div>
          </div>
        </section>
      </div>
    </>
  );
}
